input.command:
python -c "
from outlines.prompts import prompt, register_filter, unregister_filter

register_filter('shout', lambda x: x.upper() + '!')

@prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')
try:
    print(greet('world'))
except Exception as e:
    print('Error as expected:', e)
"
